250	    void disconnect(const block_id_t& src_blk,
251	        size_t src_port,
252	        const block_id_t& dst_blk,
253	        size_t dst_port) override
254	    {
255	        if (not has_block(src_blk)) {
256	            throw uhd::lookup_error(
257	                std::string("Cannot disconnect blocks, source block not found: ")
258	                + src_blk.to_string());
259	        }
260	        if (not has_block(dst_blk)) {
261	            throw uhd::lookup_error(
262	                std::string("Cannot disconnect blocks, destination block not found: ")
263	                + dst_blk.to_string());
264	        }
265	        auto edge_type = _physical_disconnect(src_blk, src_port, dst_blk, dst_port);
266	        graph_edge_t edge_info(src_port, dst_port, edge_type, true);
267	        auto src              = get_block(src_blk);
268	        auto dst              = get_block(dst_blk);
269	        edge_info.src_blockid = src->get_unique_id();
270	        edge_info.dst_blockid = dst->get_unique_id();
271	        _graph->disconnect(src.get(), dst.get(), edge_info);
272	    }
273	
274	    void connect(uhd::tx_streamer::sptr streamer,
275	        size_t strm_port,
276	        const block_id_t& dst_blk,
277	        size_t dst_port,
278	        uhd::transport::adapter_id_t adapter_id) override
279	    {
280	        // Verify the streamer was created by us
281	        auto rfnoc_streamer = std::dynamic_pointer_cast<rfnoc_tx_streamer>(streamer);
282	        if (!rfnoc_streamer) {
283	            throw uhd::type_error("Streamer is not rfnoc capable");
284	        }
285	
286	        // Verify src_blk even exists in this graph
287	        if (!has_block(dst_blk)) {
288	            throw uhd::lookup_error(
289	                std::string("Cannot connect block to streamer, source block not found: ")
290	                + dst_blk.to_string());
291	        }
292	
293	        // Verify src_blk has an SEP upstream
294	        graph_edge_t dst_static_edge = _assert_edge(
295	            _get_static_edge(
296	                [dst_blk_id = dst_blk.to_string(), dst_port](const graph_edge_t& edge) {
297	                    return edge.dst_blockid == dst_blk_id && edge.dst_port == dst_port;
298	                }),
299	            dst_blk.to_string());
300	        if (block_id_t(dst_static_edge.src_blockid).get_block_name() != NODE_ID_SEP) {
301	            const std::string err_msg =
302	                dst_blk.to_string() + ":" + std::to_string(dst_port)
303	                + " is not connected to an SEP! Routing impossible.";
304	            UHD_LOG_ERROR(LOG_ID, err_msg);
305	            throw uhd::routing_error(err_msg);
306	        }
307	
308	        // Now get the name and address of the SEP
309	        const std::string sep_block_id = dst_static_edge.src_blockid;
310	        const sep_addr_t sep_addr      = _sep_map.at(sep_block_id);
311	
312	        const sw_buff_t pyld_fmt =
313	            bits_to_sw_buff(rfnoc_streamer->get_otw_item_comp_bit_width());
314	        const sw_buff_t mdata_fmt = BUFF_U64;
315	
316	        auto xport = _gsm->create_host_to_device_data_stream(sep_addr,
317	            pyld_fmt,
318	            mdata_fmt,
319	            adapter_id,
320	            rfnoc_streamer->get_stream_args().args,
321	            rfnoc_streamer->get_unique_id());
322	
323	        rfnoc_streamer->connect_channel(strm_port, std::move(xport));
324	
325	        // If this worked, then also connect the streamer in the BGL graph
326	        auto dst = get_block(dst_blk);
327	        graph_edge_t edge_info(strm_port, dst_port, graph_edge_t::TX_STREAM, true);
328	        _graph->connect(rfnoc_streamer.get(), dst.get(), edge_info);
329	
330	        _tx_streamers[rfnoc_streamer->get_unique_id()].node = rfnoc_streamer.get();
331	        _tx_streamers[rfnoc_streamer->get_unique_id()].connections[strm_port] = {
332	            rfnoc_streamer.get(), dst.get(), edge_info};
333	    }
