335	    void connect(const block_id_t& src_blk,
336	        size_t src_port,
337	        uhd::rx_streamer::sptr streamer,
338	        size_t strm_port,
339	        uhd::transport::adapter_id_t adapter_id) override
340	    {
341	        // Verify the streamer was created by us
342	        auto rfnoc_streamer = std::dynamic_pointer_cast<rfnoc_rx_streamer>(streamer);
343	        if (!rfnoc_streamer) {
344	            throw uhd::type_error("Streamer is not rfnoc capable");
345	        }
346	
347	        // Verify src_blk even exists in this graph
348	        if (!has_block(src_blk)) {
349	            throw uhd::lookup_error(
350	                std::string("Cannot connect block to streamer, source block not found: ")
351	                + src_blk.to_string());
352	        }
353	
354	        // Verify src_blk has an SEP downstream
355	        graph_edge_t src_static_edge = _assert_edge(
356	            _get_static_edge(
357	                [src_blk_id = src_blk.to_string(), src_port](const graph_edge_t& edge) {
358	                    return edge.src_blockid == src_blk_id && edge.src_port == src_port;
359	                }),
360	            src_blk.to_string());
361	        if (block_id_t(src_static_edge.dst_blockid).get_block_name() != NODE_ID_SEP) {
362	            const std::string err_msg =
363	                src_blk.to_string() + ":" + std::to_string(src_port)
364	                + " is not connected to an SEP! Routing impossible.";
365	            UHD_LOG_ERROR(LOG_ID, err_msg);
366	            throw uhd::routing_error(err_msg);
367	        }
368	
369	        // Now get the name and address of the SEP
370	        const std::string sep_block_id = src_static_edge.dst_blockid;
371	        const sep_addr_t sep_addr      = _sep_map.at(sep_block_id);
372	
373	        const sw_buff_t pyld_fmt =
374	            bits_to_sw_buff(rfnoc_streamer->get_otw_item_comp_bit_width());
375	        const sw_buff_t mdata_fmt = BUFF_U64;
376	
377	        auto xport = _gsm->create_device_to_host_data_stream(sep_addr,
378	            pyld_fmt,
379	            mdata_fmt,
380	            adapter_id,
381	            rfnoc_streamer->get_stream_args().args,
382	            rfnoc_streamer->get_unique_id());
383	
384	        rfnoc_streamer->connect_channel(strm_port, std::move(xport));
385	
386	        // If this worked, then also connect the streamer in the BGL graph
387	        auto src = get_block(src_blk);
388	        graph_edge_t edge_info(src_port, strm_port, graph_edge_t::RX_STREAM, true);
389	        _graph->connect(src.get(), rfnoc_streamer.get(), edge_info);
390	
391	        _rx_streamers[rfnoc_streamer->get_unique_id()].node = rfnoc_streamer.get();
392	        _rx_streamers[rfnoc_streamer->get_unique_id()].connections[strm_port] = {
393	            src.get(), rfnoc_streamer.get(), edge_info};
394	    }
