396	    void disconnect(const std::string& streamer_id) override
397	    {
398	        UHD_LOG_TRACE(LOG_ID, std::string("Disconnecting ") + streamer_id);
399	        if (_tx_streamers.count(streamer_id)) {
400	            // TODO: Physically disconnect all connections
401	            // This may not be strictly necessary because the destruction of
402	            // the xport will prevent packets from being sent to the
403	            // destination.
404	
405	            // Remove the node from the graph
406	            _graph->remove(_tx_streamers[streamer_id].node);
407	
408	            // Remove the streamer from the map
409	            _tx_streamers.erase(streamer_id);
410	        } else if (_rx_streamers.count(streamer_id)) {
411	            // TODO: Physically disconnect all connections
412	
413	            // Remove the node from the graph (logically disconnect)
414	            _graph->remove(_rx_streamers[streamer_id].node);
415	
416	            // Remove the streamer from the map
417	            _rx_streamers.erase(streamer_id);
418	        }
419	        UHD_LOG_TRACE(LOG_ID, std::string("Disconnected ") + streamer_id);
420	    }
421	
422	    void disconnect(const std::string& streamer_id, size_t port) override
423	    {
424	        std::string id_str = streamer_id + ":" + std::to_string(port);
425	        UHD_LOG_TRACE(LOG_ID, std::string("Disconnecting ") + id_str);
426	        if (_tx_streamers.count(streamer_id)) {
427	            if (_tx_streamers[streamer_id].connections.count(port)) {
428	                auto connection = _tx_streamers[streamer_id].connections[port];
429	                _graph->disconnect(connection.src, connection.dst, connection.edge);
430	                _tx_streamers[streamer_id].connections.erase(port);
431	            } else {
432	                throw uhd::lookup_error(
433	                    std::string("Cannot disconnect. Port not connected: ") + id_str);
434	            }
435	        } else if (_rx_streamers.count(streamer_id)) {
436	            if (_rx_streamers[streamer_id].connections.count(port)) {
437	                auto connection = _rx_streamers[streamer_id].connections[port];
438	                // TODO: Physically disconnect port
439	                _graph->disconnect(connection.src, connection.dst, connection.edge);
440	                _rx_streamers[streamer_id].connections.erase(port);
441	            } else {
442	                throw uhd::lookup_error(
443	                    std::string("Cannot disconnect. Port not connected: ") + id_str);
444	            }
445	        }
446	        UHD_LOG_TRACE(LOG_ID, std::string("Disconnected ") + id_str);
447	    }
