488	    bool synchronize_devices(const uhd::time_spec_t& time_spec, const bool quiet) override
489	    {
490	        auto mb_controllers_copy = _mb_controllers;
491	        bool result =
492	            _mb_controllers.at(0)->synchronize(mb_controllers_copy, time_spec, quiet);
493	        if (mb_controllers_copy.size() != _mb_controllers.size()) {
494	            // This shouldn't happen until we allow different device types in a
495	            // rfnoc_graph
496	            UHD_LOG_ERROR(LOG_ID, "Some devices wouldn't be sync'd!");
497	            return false;
498	        }
499	        return result;
500	    }
