507	    std::vector<uhd::transport::adapter_id_t> enumerate_adapters_to_dst(
508	        const block_id_t& dst_blk, size_t dst_port) override
509	    {
510	        // Verify dst_blk even exists in this graph
511	        if (!has_block(dst_blk)) {
512	            throw uhd::lookup_error(
513	                std::string("Cannot connect block to streamer, source block not found: ")
514	                + dst_blk.to_string());
515	        }
516	
517	        // Verify dst_blk has an SEP upstream
518	        graph_edge_t dst_static_edge = _assert_edge(
519	            _get_static_edge(
520	                [dst_blk_id = dst_blk.to_string(), dst_port](const graph_edge_t& edge) {
521	                    return edge.dst_blockid == dst_blk_id && edge.dst_port == dst_port;
522	                }),
523	            dst_blk.to_string());
524	        if (block_id_t(dst_static_edge.src_blockid).get_block_name() != NODE_ID_SEP) {
525	            const std::string err_msg =
526	                dst_blk.to_string() + ":" + std::to_string(dst_port)
527	                + " is not connected to an SEP! Routing impossible.";
528	            UHD_LOG_ERROR(LOG_ID, err_msg);
529	            throw uhd::routing_error(err_msg);
530	        }
531	
532	        // Now get the name and address of the SEP
533	        const std::string sep_block_id = dst_static_edge.src_blockid;
534	        const sep_addr_t sep_addr      = _sep_map.at(sep_block_id);
535	
536	        // Find links that can reach the SEP
537	        return _gsm->get_adapters(sep_addr);
538	    }
539	
540	    std::vector<uhd::transport::adapter_id_t> enumerate_adapters_from_src(
541	        const block_id_t& src_blk, size_t src_port) override
542	    {
543	        // Verify src_blk even exists in this graph
544	        if (!has_block(src_blk)) {
545	            throw uhd::lookup_error(
546	                std::string("Cannot connect block to streamer, source block not found: ")
547	                + src_blk.to_string());
548	        }
549	
550	        // Verify src_blk has an SEP downstream
551	        graph_edge_t src_static_edge = _assert_edge(
552	            _get_static_edge(
553	                [src_blk_id = src_blk.to_string(), src_port](const graph_edge_t& edge) {
554	                    return edge.src_blockid == src_blk_id && edge.src_port == src_port;
555	                }),
556	            src_blk.to_string());
557	        if (block_id_t(src_static_edge.dst_blockid).get_block_name() != NODE_ID_SEP) {
558	            const std::string err_msg =
559	                src_blk.to_string() + ":" + std::to_string(src_port)
560	                + " is not connected to an SEP! Routing impossible.";
561	            UHD_LOG_ERROR(LOG_ID, err_msg);
562	            throw uhd::routing_error(err_msg);
563	        }
564	
565	        // Now get the name and address of the SEP
566	        const std::string sep_block_id = src_static_edge.dst_blockid;
567	        const sep_addr_t sep_addr      = _sep_map.at(sep_block_id);
568	
569	        // Find links that can reach the SEP
570	        return _gsm->get_adapters(sep_addr);
571	    }
