633	    void _init_gsm()
634	    {
635	        UHD_LOG_TRACE(LOG_ID, "Initializing GSM...");
636	        auto e2s = [](uhd::endianness_t endianness) {
637	            return endianness == uhd::ENDIANNESS_BIG ? "BIG" : "LITTLE";
638	        };
639	        const chdr_w_t chdr_w              = _device->get_mb_iface(0).get_chdr_w();
640	        const uhd::endianness_t endianness = _device->get_mb_iface(0).get_endianness();
641	        for (size_t mb_idx = 1; mb_idx < _num_mboards; mb_idx++) {
642	            if (_device->get_mb_iface(mb_idx).get_chdr_w() != chdr_w) {
643	                throw uhd::runtime_error(
644	                    std::string("Non-homogenous devices: Graph CHDR width is ")
645	                    + std::to_string(chdr_w_to_bits(chdr_w)) + " but device "
646	                    + std::to_string(mb_idx) + " has CHDR width of "
647	                    + std::to_string(
648	                        chdr_w_to_bits(_device->get_mb_iface(mb_idx).get_chdr_w()))
649	                    + " bits!");
650	            }
651	            if (_device->get_mb_iface(mb_idx).get_endianness() != endianness) {
652	                throw uhd::runtime_error(
653	                    std::string("Non-homogenous devices: Graph endianness is ")
654	                    + e2s(endianness) + " but device " + std::to_string(mb_idx)
655	                    + " has endianness " + e2s(endianness) + "!");
656	            }
657	        }
658	        UHD_LOG_TRACE(LOG_ID,
659	            "Creating packet factory with CHDR width "
660	                << chdr_w_to_bits(chdr_w) << " bits and endianness " << e2s(endianness));
661	        _pkt_factory = std::make_unique<chdr::chdr_packet_factory>(chdr_w, endianness);
662	        // Create a collection of link definitions: (ID, MB) pairs
663	        std::vector<std::pair<device_id_t, mb_iface*>> links;
664	        for (size_t mb_idx = 0; mb_idx < _num_mboards; mb_idx++) {
665	            const auto device_ids = _device->get_mb_iface(mb_idx).get_local_device_ids();
666	            for (const device_id_t local_device_id : device_ids) {
667	                if (_device->get_mb_iface(mb_idx).get_endianness(local_device_id)
668	                    != endianness) {
669	                    throw uhd::runtime_error(
670	                        std::string("Non-homogenous devices: Graph endianness is ")
671	                        + e2s(endianness) + " but device " + std::to_string(mb_idx)
672	                        + " has endianness " + e2s(endianness) + "!");
673	                }
674	                links.push_back(
675	                    std::make_pair(local_device_id, &_device->get_mb_iface(mb_idx)));
676	            }
677	        }
678	        if (links.empty()) {
679	            UHD_LOG_ERROR(
680	                LOG_ID, "No links found for " << _num_mboards << " motherboards!");
681	            throw uhd::runtime_error("[rfnoc_graph] No links found!");
682	        }
683	        UHD_LOG_TRACE(LOG_ID, "Found a total of " << links.size() << " links.");
684	        try {
685	            _gsm = graph_stream_manager::make(*_pkt_factory, _epid_alloc, links);
686	        } catch (uhd::io_error& ex) {
687	            UHD_LOG_ERROR(LOG_ID, "IO Error during GSM initialization. " << ex.what());
688	            throw;
689	        }
690	
691	        // Configure endpoint_manager, make sure all routes are established
692	        // FIXME
693	    }
694	
695	    // Initialize client zero and all block controllers for motherboard mb_idx
696	    void _init_blocks(const size_t mb_idx, const uhd::device_addr_t& dev_addr)
697	    {
698	        UHD_LOG_TRACE(LOG_ID, "Initializing blocks for MB " << mb_idx << "...");
699	        // Setup the interfaces for this mboard and get some configuration info
700	        mb_iface& mb = _device->get_mb_iface(mb_idx);
701	        // Ask GSM to allow us to talk to our remote mb
702	        sep_addr_t ctrl_sep_addr(mb.get_remote_device_id(), 0);
703	        _gsm->connect_host_to_device(ctrl_sep_addr);
704	        // Grab and stash the Client Zero for this mboard
705	        detail::client_zero::sptr mb_cz = _gsm->get_client_zero(ctrl_sep_addr);
706	        // Client zero port numbers are based on the control xbar numbers,
707	        // which have the client 0 interface first, followed by stream
708	        // endpoints, and then the blocks.
709	        _client_zeros.emplace(mb_idx, mb_cz);
710	
711	        const size_t num_blocks       = mb_cz->get_num_blocks();
712	        const size_t first_block_port = 1 + mb_cz->get_num_stream_endpoints();
713	
714	        /* Flush and reset each block in the mboard
715	         * We do this before we enumerate the blocks to ensure they're in a clean
716	         * state before we construct their block controller, and so that we don't
717	         * reset any setting that the block controller writes
718	         */
719	        UHD_LOG_TRACE(LOG_ID,
720	            std::string("Flushing and resetting blocks on mboard ")
721	                + std::to_string(mb_idx));
722	        _flush_and_reset_mboard(mb_cz, num_blocks, first_block_port);
723	
724	        // Make a map to count the number of each block we have
725	        std::unordered_map<std::string, uint16_t> block_count_map;
726	
727	        // Iterate through and register each of the blocks in this mboard
728	        for (size_t portno = 0; portno < num_blocks; ++portno) {
729	            const auto noc_id       = mb_cz->get_noc_id(portno + first_block_port);
730	            const auto device_type  = mb_cz->get_device_type();
731	            auto block_factory_info = factory::get_block_factory(noc_id, device_type);
732	            auto block_info         = mb_cz->get_block_info(portno + first_block_port);
733	            block_id_t block_id(mb_idx,
734	                block_factory_info.block_name,
735	                block_count_map[block_factory_info.block_name]++);
736	            // Get access to the clock interface objects. We have some rules
737	            // here:
738	            // - The ctrlport clock must always be provided through the
739	            //   BSP via mb_iface
740	            // - The timebase clock can be set to CLOCK_KEY_GRAPH, which means
741	            //   the block takes care of the timebase itself (via property
742	            //   propagation). In that case, we generate a clock iface
743	            //   object on the fly here.
744	            // - In all other cases, the BSP must provide us that clock
745	            //   iface object through the mb_iface
746	            auto ctrlport_clk_iface = mb.get_clock_iface(
747	                block_factory_info.ctrlport_clk, block_info.ctrl_clk_idx);
748	            auto tb_clk_iface = (block_factory_info.timebase_clk == CLOCK_KEY_GRAPH)
749	                                    ? std::make_shared<clock_iface>(CLOCK_KEY_GRAPH)
750	                                    : mb.get_clock_iface(block_factory_info.timebase_clk,
751	                                        block_info.tb_clk_idx);
752	            // A "graph" clock is always "running"
753	            if (block_factory_info.timebase_clk == CLOCK_KEY_GRAPH) {
754	                tb_clk_iface->set_running(true);
755	            }
756	            auto block_reg_iface = _gsm->get_block_register_iface(
757	                ctrl_sep_addr, portno, *ctrlport_clk_iface.get(), *tb_clk_iface.get());
758	            block_reg_iface->set_log_id(block_id.to_string());
759	            auto make_args_uptr =
760	                noc_block_base::make_args_ptr(new noc_block_base::make_args_int_t());
761	            make_args_uptr->noc_id           = noc_id;
762	            make_args_uptr->block_id         = block_id;
763	            make_args_uptr->num_input_ports  = block_info.num_inputs;
764	            make_args_uptr->num_output_ports = block_info.num_outputs;
765	            make_args_uptr->mtu =
766	                (1 << block_info.data_mtu) * chdr_w_to_bits(mb.get_chdr_w()) / 8;
767	            make_args_uptr->chdr_w             = mb.get_chdr_w();
768	            make_args_uptr->reg_iface          = block_reg_iface;
769	            make_args_uptr->tb_clk_iface       = tb_clk_iface;
770	            make_args_uptr->ctrlport_clk_iface = ctrlport_clk_iface;
771	            make_args_uptr->mb_control =
772	                block_factory_info.mb_access ? _mb_controllers.at(mb_idx) : nullptr;
773	            const uhd::fs_path block_path(uhd::fs_path("/blocks") / block_id.to_string());
774	            _tree->create<uint32_t>(block_path / "noc_id").set(noc_id);
775	            make_args_uptr->tree = _tree->subtree(block_path);
776	            make_args_uptr->args = dev_addr; // TODO filter the device args
777	            try {
778	                _block_registry->register_block(
779	                    block_factory_info.factory_fn(std::move(make_args_uptr)));
780	                block_initializer::post_init(_block_registry->get_block(block_id));
781	            } catch (...) {
782	                UHD_LOG_ERROR(
783	                    LOG_ID, "Error during initialization of block " << block_id << "!");
784	                throw;
785	            }
786	            _xbar_block_config[block_id.to_string()] = {
787	                portno, noc_id, block_id.get_block_count()};
788	
789	            _port_block_map.insert({{mb_idx, portno + first_block_port}, block_id});
790	        }
791	    }
792	
793	    void _init_sep_map()
794	    {
795	        for (size_t mb_idx = 0; mb_idx < _num_mboards; ++mb_idx) {
796	            auto remote_device_id = _device->get_mb_iface(mb_idx).get_remote_device_id();
797	            auto& cz              = _client_zeros.at(mb_idx);
798	            for (size_t sep_idx = 0; sep_idx < cz->get_num_stream_endpoints();
799	                 ++sep_idx) {
800	                // Register ID in _port_block_map
801	                block_id_t id(mb_idx, NODE_ID_SEP, sep_idx);
802	                _port_block_map.insert({{mb_idx, sep_idx + 1}, id});
803	                _sep_map.insert({id.to_string(), sep_addr_t(remote_device_id, sep_idx)});
804	            }
805	        }
806	    }
