850	    void _connect(std::shared_ptr<node_t> src_blk,
851	        size_t src_port,
852	        std::shared_ptr<node_t> dst_blk,
853	        size_t dst_port,
854	        graph_edge_t::edge_t edge_type,
855	        bool is_back_edge)
