984	    //! Flush and reset each connected port on the mboard
985	    void _flush_and_reset_mboard(detail::client_zero::sptr mb_cz,
986	        const size_t num_blocks,
987	        const size_t first_block_port)
988	    {
989	        if (!mb_cz->complete_flush_all_blocks()) {
990	            UHD_LOG_WARNING(LOG_ID, "One or more blocks timed out during flush!");
991	        }
992	
993	        // Reset
994	        for (size_t portno = 0; portno < num_blocks; ++portno) {
995	            auto block_portno = portno + first_block_port;
996	            mb_cz->reset_chdr(block_portno);
997	            mb_cz->reset_ctrl(block_portno);
998	        }
999	    }
1000	
1001	    /*! Find the static edge that matches \p pred
1002	     *
1003	     * \throws uhd::assertion_error if the edge can't be found. So be careful!
1004	     */
1005	    template <typename UnaryPredicate>
1006	    boost::optional<graph_edge_t> _get_static_edge(UnaryPredicate&& pred)
1007	    {
1008	        auto edge_it = std::find_if(_static_edges.cbegin(), _static_edges.cend(), pred);
1009	        if (edge_it == _static_edges.cend()) {
1010	            return boost::none;
1011	        }
1012	        return *edge_it;
1013	    }
1014	
1015	    /*! Make sure an optional edge info is valid, or throw.
1016	     */
1017	    graph_edge_t _assert_edge(
1018	        boost::optional<graph_edge_t> edge_o, const std::string& blk_info)
1019	    {
1020	        if (!bool(edge_o)) {
1021	            const std::string err_msg = std::string("Cannot connect block ") + blk_info
1022	                                        + ", port is unconnected in the FPGA!";
1023	            UHD_LOG_ERROR(LOG_ID, err_msg);
1024	            throw uhd::routing_error(err_msg);
1025	        }
1026	        return edge_o.get();
1027	    }
1028	
1029	    /**************************************************************************
1030	     * Attributes
1031	     *************************************************************************/
1032	    //! Reference to the underlying device implementation
1033	    detail::rfnoc_device::sptr _device;
1034	
1035	    //! Reference to the property tree
1036	    uhd::property_tree::sptr _tree;
1037	
1038	    //! Number of motherboards, this is technically redundant but useful for
1039	    // easy lookups.
1040	    size_t _num_mboards;
1041	
1042	    //! Reference to the global I/O Service Manager
1043	    uhd::usrp::io_service_mgr::sptr _io_srv_mgr;
1044	
1045	    //! Registry for the blocks (it's a separate class)
1046	    std::unique_ptr<detail::block_container_t> _block_registry;
1047	
1048	    /*! Registry for the actual block connections on the crossbar
1049	     *  When we register blocks in the _block_registry, we also need to store some
1050	     * information in this map so we can easily figure out which crossbar port a block
1051	     * controller is connected to
1052	     * \p keys are the string representation of the block ID
1053	     * \p values are the block crossbar information structs
1054	     * TODO: change from string block IDs to block_id_t with COOL custom hashing
1055	     */
1056	    std::unordered_map<std::string, block_xbar_info> _xbar_block_config;
1057	
1058	    //! Reference to the graph
1059	    std::unique_ptr<detail::graph_t> _graph;
1060	
1061	    //! Stash a list of motherboard controllers
1062	    std::vector<mb_controller::sptr> _mb_controllers;
1063	
1064	    //! Stash of the client zeros for all motherboards
1065	    std::unordered_map<size_t, detail::client_zero::sptr> _client_zeros;
1066	
1067	    //! Map a pair (motherboard index, control crossbar port) to an RFNoC block
1068	    // or SEP
1069	    std::map<std::pair<size_t, size_t>, block_id_t> _port_block_map;
1070	
1071	    //! Map SEP block ID (e.g. 0/SEP#0) onto a sep_addr_t
1072	    std::unordered_map<std::string, sep_addr_t> _sep_map;
1073	
1074	    //! List of statically connected edges. Includes SEPs too!
1075	    std::vector<graph_edge_t> _static_edges;
1076	
1077	    //! uptr to graph stream manager
1078	    graph_stream_manager::uptr _gsm;
1079	
1080	    //! EPID allocator. Technically not required by the rfnoc_graph, but we'll
1081	    // store it here because it's such a central thing.
1082	    epid_allocator::sptr _epid_alloc = std::make_shared<epid_allocator>();
1083	
1084	    //! Reference to a packet factory object. Gets initialized just before the GSM
1085	    std::unique_ptr<chdr::chdr_packet_factory> _pkt_factory;
1086	
1087	    //! Map from TX streamer ID to streamer info
1088	    std::map<std::string, streamer_info_t> _tx_streamers;
1089	
1090	    //! Map from RX streamer ID to streamer info
1091	    std::map<std::string, streamer_info_t> _rx_streamers;
1092	}; /* class rfnoc_graph_impl */
1093	
1094	
1095	/******************************************************************************
1096	 * Factory
1097	 *****************************************************************************/
1098	namespace uhd { namespace rfnoc { namespace detail {
1099	
1100	// Simple factory: If we already have the device, simply pass it on
1101	rfnoc_graph::sptr make_rfnoc_graph(
1102	    detail::rfnoc_device::sptr dev, const uhd::device_addr_t& device_addr)
1103	{
1104	    static std::mutex _map_mutex;
1105	    static std::map<std::weak_ptr<rfnoc_device>,
1106	        std::weak_ptr<rfnoc_graph>,
1107	        std::owner_less<std::weak_ptr<rfnoc_device>>>
1108	        dev_to_graph;
1109	    rfnoc_graph::sptr graph;
1110	
1111	    // Check if a graph was already created for this device
1112	    std::lock_guard<std::mutex> lock(_map_mutex);
1113	    if (dev_to_graph.count(dev)) {
1114	        if (rfnoc_graph::sptr p = dev_to_graph[dev].lock()) {
1115	            return p;
1116	        }
1117	    }
1118	
1119	    // Create a new graph
1120	    graph             = std::make_shared<rfnoc_graph_impl>(dev, device_addr);
1121	    dev_to_graph[dev] = graph;
1122	    return graph;
1123	}
1124	
1125	}}} /* namespace uhd::rfnoc::detail */
1126	
1127	// If we don't have a device yet, create it and see if it's really an RFNoC
1128	// device. This is used by multi_usrp_rfnoc, for example.
1129	rfnoc_graph::sptr rfnoc_graph::make(const uhd::device_addr_t& device_addr)
1130	{
1131	    auto dev =
1132	        std::dynamic_pointer_cast<detail::rfnoc_device>(uhd::device::make(device_addr));
1133	    if (!dev) {
1134	        throw uhd::key_error(std::string("No RFNoC devices found for ----->\n")
1135	                             + device_addr.to_pp_string());
1136	    }
1137	    return detail::make_rfnoc_graph(dev, device_addr);
1138	}
