38	template <typename samp_type>
39	void recv_to_file(uhd::rx_streamer::sptr rx_stream,
40	    const std::string& file,
41	    const size_t samps_per_buff,
42	    const double rx_rate,
43	    const unsigned long long num_requested_samples,
44	    double time_requested       = 0.0,
45	    bool bw_summary             = false,
46	    bool stats                  = false,
47	    bool enable_size_map        = false,
48	    bool continue_on_bad_packet = false)
49	{
50	    unsigned long long num_total_samps = 0;
51	
52	    uhd::rx_metadata_t md;
53	    std::vector<samp_type> buff(samps_per_buff);
54	    std::ofstream outfile;
55	    if (not file.empty()) {
56	        outfile.open(file.c_str(), std::ofstream::binary);
57	    }
58	    bool overflow_message = true;
59	
60	    // setup streaming
61	    uhd::stream_cmd_t stream_cmd((num_requested_samples == 0)
62	                                     ? uhd::stream_cmd_t::STREAM_MODE_START_CONTINUOUS
63	                                     : uhd::stream_cmd_t::STREAM_MODE_NUM_SAMPS_AND_DONE);
64	    stream_cmd.num_samps  = size_t(num_requested_samples);
65	    stream_cmd.stream_now = true;
66	    stream_cmd.time_spec  = uhd::time_spec_t();
67	    std::cout << "Issuing stream cmd" << std::endl;
68	    rx_stream->issue_stream_cmd(stream_cmd);
69	
70	    const auto start_time = std::chrono::steady_clock::now();
71	    const auto stop_time =
72	        start_time + std::chrono::milliseconds(int64_t(1000 * time_requested));
73	    // Track time and samps between updating the BW summary
74	    auto last_update                     = start_time;
75	    unsigned long long last_update_samps = 0;
76	
77	    typedef std::map<size_t, size_t> SizeMap;
78	    SizeMap mapSizes;
79	
80	    // Run this loop until either time expired (if a duration was given), until
81	    // the requested number of samples were collected (if such a number was
82	    // given), or until Ctrl-C was pressed.
83	    while (not stop_signal_called
84	           and (num_requested_samples != num_total_samps or num_requested_samples == 0)
85	           and (time_requested == 0.0 or std::chrono::steady_clock::now() <= stop_time)) {
86	        const auto now = std::chrono::steady_clock::now();
87	
88	        size_t num_rx_samps =
89	            rx_stream->recv(&buff.front(), buff.size(), md, 3.0, enable_size_map);
90	
91	        if (md.error_code == uhd::rx_metadata_t::ERROR_CODE_TIMEOUT) {
92	            std::cout << "Timeout while streaming" << std::endl;
93	            break;
94	        }
95	        if (md.error_code == uhd::rx_metadata_t::ERROR_CODE_OVERFLOW) {
96	            if (overflow_message) {
97	                overflow_message = false;
98	                std::cerr
99	                    << "Got an overflow indication. Please consider the following:\n"
100	                       "  Your write medium must sustain a rate of "
101	                    << (rx_rate * sizeof(samp_type) / 1e6)
102	                    << "MB/s.\n"
103	                       "  Dropped samples will not be written to the file.\n"
104	                       "  Please modify this example for your purposes.\n"
105	                       "  This message will not appear again.\n";
106	            }
107	            continue;
108	        }
109	        if (md.error_code != uhd::rx_metadata_t::ERROR_CODE_NONE) {
110	            std::string error = std::string("Receiver error: ") + md.strerror();
111	            if (continue_on_bad_packet) {
112	                std::cerr << error << std::endl;
113	                continue;
114	            } else
115	                throw std::runtime_error(error);
116	        }
117	
118	        if (enable_size_map) {
119	            SizeMap::iterator it = mapSizes.find(num_rx_samps);
120	            if (it == mapSizes.end())
121	                mapSizes[num_rx_samps] = 0;
122	            mapSizes[num_rx_samps] += 1;
123	        }
124	
125	        num_total_samps += num_rx_samps;
126	
127	        if (outfile.is_open()) {
128	            outfile.write((const char*)&buff.front(), num_rx_samps * sizeof(samp_type));
129	        }
130	
131	        if (bw_summary) {
132	            last_update_samps += num_rx_samps;
133	            const auto time_since_last_update = now - last_update;
134	            if (time_since_last_update > std::chrono::seconds(UPDATE_INTERVAL)) {
135	                const double time_since_last_update_s =
136	                    std::chrono::duration<double>(time_since_last_update).count();
137	                const double rate = double(last_update_samps) / time_since_last_update_s;
138	                std::cout << "\t" << (rate / 1e6) << " MSps" << std::endl;
139	                last_update_samps = 0;
140	                last_update       = now;
141	            }
142	        }
143	    }
144	    const auto actual_stop_time = std::chrono::steady_clock::now();
145	
146	    stream_cmd.stream_mode = uhd::stream_cmd_t::STREAM_MODE_STOP_CONTINUOUS;
147	    std::cout << "Issuing stop stream cmd" << std::endl;
148	    rx_stream->issue_stream_cmd(stream_cmd);
149	
150	    // Run recv until nothing is left
151	    int num_post_samps = 0;
152	    do {
153	        num_post_samps = rx_stream->recv(&buff.front(), buff.size(), md, 3.0);
154	    } while (num_post_samps and md.error_code == uhd::rx_metadata_t::ERROR_CODE_NONE);
155	
156	    if (outfile.is_open())
157	        outfile.close();
158	
159	    if (stats) {
160	        std::cout << std::endl;
161	
162	        const double actual_duration_seconds =
163	            std::chrono::duration<float>(actual_stop_time - start_time).count();
164	
165	        std::cout << "Received " << num_total_samps << " samples in "
166	                  << actual_duration_seconds << " seconds" << std::endl;
167	        const double rate = (double)num_total_samps / actual_duration_seconds;
168	        std::cout << (rate / 1e6) << " MSps" << std::endl;
169	
170	        if (enable_size_map) {
171	            std::cout << std::endl;
172	            std::cout << "Packet size map (bytes: count)" << std::endl;
173	            for (SizeMap::iterator it = mapSizes.begin(); it != mapSizes.end(); it++)
174	                std::cout << it->first << ":\t" << it->second << std::endl;
175	        }
176	    }
177	}
