400	
401	    bool bw_summary = vm.count("progress") > 0;
402	    bool stats      = vm.count("stats") > 0;
403	    if (vm.count("null") > 0) {
404	        file = "";
405	    }
406	    bool enable_size_map        = vm.count("sizemap") > 0;
407	    bool continue_on_bad_packet = vm.count("continue") > 0;
408	
409	    if (enable_size_map) {
410	        std::cout << "Packet size tracking enabled - will only recv one packet at a time!"
411	                  << std::endl;
412	    }
413	
414	    if (format != "sc16" and format != "fc32" and format != "fc64") {
415	        std::cout << "Invalid sample format: " << format << std::endl;
416	        return EXIT_FAILURE;
417	    }
418	
419	    /************************************************************************
420	     * Create device and block controls
421	     ***********************************************************************/
422	    std::cout << std::endl;
423	    std::cout << "Creating the RFNoC graph with args: " << args << std::endl;
424	    auto graph = uhd::rfnoc::rfnoc_graph::make(args);
425	
426	    // Create handle for radio object (e.g. 0/Radio#0)
427	    uhd::rfnoc::block_id_t radio_ctrl_id(0, "Radio", radio_id);
428	    // This next line will fail if the radio is not actually available
429	    auto radio_ctrl = graph->get_block<uhd::rfnoc::radio_control>(radio_ctrl_id);
430	    std::cout << "Using radio " << radio_id << ", channel " << radio_chan << std::endl;
431	
432	    uhd::rfnoc::block_id_t last_block_in_chain;
433	    size_t last_port_in_chain;
434	    uhd::rfnoc::ddc_block_control::sptr ddc_ctrl;
435	    size_t ddc_chan       = 0;
436	    bool user_block_found = false;
437	
438	    { // First, connect everything dangling off of the radio
439	        auto edges = uhd::rfnoc::get_block_chain(graph, radio_ctrl_id, radio_chan, true);
440	        last_block_in_chain = edges.back().src_blockid;
441	        last_port_in_chain  = edges.back().src_port;
442	        if (edges.size() > 1) {
443	            uhd::rfnoc::connect_through_blocks(graph,
444	                radio_ctrl_id,
445	                radio_chan,
446	                last_block_in_chain,
447	                last_port_in_chain);
448	            for (auto& edge : edges) {
449	                if (uhd::rfnoc::block_id_t(edge.dst_blockid).get_block_name() == "DDC") {
450	                    ddc_ctrl =
451	                        graph->get_block<uhd::rfnoc::ddc_block_control>(edge.dst_blockid);
452	                    ddc_chan = edge.dst_port;
453	                }
454	                if (vm.count("block-id") && edge.dst_blockid == block_id) {
455	                    user_block_found = true;
456	                }
457	            }
458	        }
459	    }
460	
461	    // If the user block is not in the chain yet, see if we can connect that
462	    // separately
463	    if (vm.count("block-id") && !user_block_found) {
464	        const auto user_block_id = uhd::rfnoc::block_id_t(block_id);
465	        if (!graph->has_block(user_block_id)) {
466	            std::cout << "ERROR! No such block: " << block_id << std::endl;
467	            return EXIT_FAILURE;
468	        }
469	        std::cout << "Attempting to connect " << block_id << ":" << last_port_in_chain
470	                  << " to " << last_block_in_chain << ":" << block_port << "..."
471	                  << std::endl;
472	        uhd::rfnoc::connect_through_blocks(
473	            graph, last_block_in_chain, last_port_in_chain, user_block_id, block_port);
474	        last_block_in_chain = uhd::rfnoc::block_id_t(block_id);
475	        last_port_in_chain  = block_port;
476	        // Now we have to make sure that there are no more static connections
477	        // after the user-defined block
478	        auto edges = uhd::rfnoc::get_block_chain(
479	            graph, last_block_in_chain, last_port_in_chain, true);
480	        if (edges.size() > 1) {
481	            uhd::rfnoc::connect_through_blocks(graph,
482	                last_block_in_chain,
483	                last_port_in_chain,
484	                edges.back().src_blockid,
485	                edges.back().src_port);
486	            last_block_in_chain = edges.back().src_blockid;
487	            last_port_in_chain  = edges.back().src_port;
488	        }
489	    }
490	    /************************************************************************
491	     * Set up radio
492	     ***********************************************************************/
493	    // Lock mboard clocks
494	    if (vm.count("ref")) {
495	        graph->get_mb_controller(0)->set_clock_source(ref);
496	    }
497	
498	    // set the rf gain
499	    if (vm.count("gain")) {
500	        std::cout << "Requesting RX Gain: " << gain << " dB..." << std::endl;
501	        radio_ctrl->set_rx_gain(gain, radio_chan);
502	        std::cout << "Actual RX Gain: " << radio_ctrl->get_rx_gain(radio_chan) << " dB..."
503	                  << std::endl
504	                  << std::endl;
505	    }
506	
507	    // set the IF filter bandwidth
508	    if (vm.count("bw")) {
509	        std::cout << "Requesting RX Bandwidth: " << (bw / 1e6) << " MHz..." << std::endl;
510	        radio_ctrl->set_rx_bandwidth(bw, radio_chan);
511	        std::cout << "Actual RX Bandwidth: "
512	                  << (radio_ctrl->get_rx_bandwidth(radio_chan) / 1e6) << " MHz..."
513	                  << std::endl
514	                  << std::endl;
515	    }
516	
517	    // set the antenna
518	    if (vm.count("ant")) {
519	        radio_ctrl->set_rx_antenna(ant, radio_chan);
520	    }
521	
522	    if (vm.count("spp")) {
523	        std::cout << "Requesting samples per packet of: " << spp << std::endl;
524	        radio_ctrl->set_property<int>("spp", spp, radio_chan);
525	        spp = radio_ctrl->get_property<int>("spp", radio_chan);
526	        std::cout << "Actual samples per packet = " << spp << std::endl;
527	    }
528	
529	    /************************************************************************
530	     * Set up streaming
531	     ***********************************************************************/
532	    uhd::device_addr_t streamer_args(streamargs);
533	
534	    // create a receive streamer
535	    uhd::stream_args_t stream_args(
536	        format, "sc16"); // We should read the wire format from the blocks
537	    stream_args.args = streamer_args;
538	    std::cout << "Using streamer args: " << stream_args.args.to_string() << std::endl;
539	    auto rx_stream = graph->create_rx_streamer(1, stream_args);
540	
541	    // Connect streamer to last block and commit the graph
542	    graph->connect(last_block_in_chain, last_port_in_chain, rx_stream, 0);
543	    graph->commit();
544	    std::cout << "Active connections:" << std::endl;
545	    for (auto& edge : graph->enumerate_active_connections()) {
546	        std::cout << "* " << edge.to_string() << std::endl;
547	    }
548	
549	    /************************************************************************
550	     * Set up sampling rate and (optional) user block properties. We do this
551	     * after commit() so we can use the property propagation.
552	     ***********************************************************************/
553	
554	    // set the center frequency
555	    if (vm.count("freq")) {
556	        std::cout << "Requesting RX Freq: " << (freq / 1e6) << " MHz..." << std::endl;
557	        uhd::tune_request_t tune_request(freq);
558	
559	        if (vm.count("lo-offset")) {
560	            std::cout << boost::format("Setting RX LO Offset: %f MHz...")
561	                             % (lo_offset / 1e6)
562	                      << std::endl;
563	            tune_request = uhd::tune_request_t(freq, lo_offset);
564	        }
565	
566	        if (vm.count("int-n")) {
567	            tune_request.args = uhd::device_addr_t("mode_n=integer");
568	        }
569	        auto tune_req_action = uhd::rfnoc::tune_request_action_info::make(tune_request);
570	        tune_req_action->tune_request = tune_request;
571	        rx_stream->post_input_action(tune_req_action, 0);
572	
573	        std::cout << "Actual RX Freq: "
574	                  << (radio_ctrl->get_rx_frequency(radio_chan) / 1e6) << " MHz..."
575	                  << std::endl
576	                  << std::endl;
577	    }
578	
579	    // set the sample rate
580	    if (rate <= 0.0) {
581	        std::cerr << "Please specify a valid sample rate" << std::endl;
582	        return EXIT_FAILURE;
583	    }
584	    std::cout << "Requesting RX Rate: " << (rate / 1e6) << " Msps..." << std::endl;
585	    if (ddc_ctrl) {
586	        std::cout << "Setting rate on DDC block!" << std::endl;
587	        rate = ddc_ctrl->set_output_rate(rate, ddc_chan);
588	    } else {
589	        std::cout << "Setting rate on radio block!" << std::endl;
590	        rate = radio_ctrl->set_rate(rate);
591	    }
592	    std::cout << "Actual RX Rate: " << (rate / 1e6) << " Msps..." << std::endl
593	              << std::endl;
594	
595	    std::this_thread::sleep_for(std::chrono::milliseconds(int64_t(1000 * setup_time)));
596	
597	    // check Ref and LO Lock detect
598	    if (not vm.count("skip-lo")) {
599	        check_locked_sensor(
600	            radio_ctrl->get_rx_sensor_names(radio_chan),
601	            "lo_locked",
602	            [&](const std::string& sensor_name) {
603	                return radio_ctrl->get_rx_sensor(sensor_name, radio_chan);
604	            },
605	            setup_time);
606	        if (ref == "external") {
607	            check_locked_sensor(
608	                graph->get_mb_controller(0)->get_sensor_names(),
609	                "ref_locked",
610	                [&](const std::string& sensor_name) {
611	                    return graph->get_mb_controller(0)->get_sensor(sensor_name);
612	                },
613	                setup_time);
614	        }
615	    }
616	
617	    if (vm.count("block-props")) {
618	        std::cout << "Setting block properties to: " << block_props << std::endl;
619	        graph->get_block(uhd::rfnoc::block_id_t(block_id))
620	            ->set_properties(uhd::device_addr_t(block_props));
621	    }
622	
623	    if (total_num_samps == 0) {
624	        std::signal(SIGINT, &sig_int_handler);
625	        std::cout << "Press Ctrl + C to stop streaming..." << std::endl;
626	    }
627	#define recv_to_file_args() \
628	    (rx_stream,             \
629	        file,               \
630	        spb,                \
631	        rate,               \
632	        total_num_samps,    \
633	        total_time,         \
634	        bw_summary,         \
635	        stats,              \
636	        enable_size_map,    \
637	        continue_on_bad_packet)
638	    // recv to file
639	    if (format == "fc64")
640	        recv_to_file<std::complex<double>> recv_to_file_args();
641	    else if (format == "fc32")
642	        recv_to_file<std::complex<float>> recv_to_file_args();
643	    else if (format == "sc16")
644	        recv_to_file<std::complex<short>> recv_to_file_args();
645	    else
646	        throw std::runtime_error("Unknown data format: " + format);
647	
648	    // finished
649	    std::cout << std::endl << "Done!" << std::endl << std::endl;
650	
651	    return EXIT_SUCCESS;
652	}
